INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('police-8b7f1efc-moex-00127', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '在公共政策分析的方法論中，以理性模式（comprehensiverationality）與漸進模式（incrementalism） 為兩大典範，常被用於警察政策分析上，下列敘述何者正確？', '["理性模式是政治面項剖析政策，漸進模式是經濟理論的應用", "問題導向警政中的SARA模式，是漸進模式的應用", "Kingdon的「政策窗（policywindow）」理論是理性模式的應用", "「漸進理論」指出決策者不會重新審視問題，也未確定目標，而是以現行做法為基礎（thestatus quo），僅作出局部的微調，以找尋漸進的代替性政策"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "09dc69c55c4f", "answer_pdf_sha1": "00e0858a8536", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1008", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00128', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '警政倫理可由各種不同的層面加以探討，如靜態的和動態的、消極的和積極的、內部的和外部的。 下列敘述何者正確？', '["警察倫理的「靜態面」指的是人際互動的準則", "警察倫理的「動態面」指的是警察系統內成員之間的秩序關係", "警察倫理的「消極面」要求警察人員不得違反倫理規範", "警察的「外部倫理」是指貫徹警察系統內「上下、長幼、朋友」三倫精義"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "09dc69c55c4f", "answer_pdf_sha1": "00e0858a8536", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1008", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00129', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', 'Bayley（1985）認為，各國對於警察行為的控制，有內在於警察組織的課責及外在機制的課責兩 種做法。下列關於警察課責（accountability）機制的敘述，何者錯誤？', '["外在的專責控制機制（External-Exclusive），可以是單一的或多元的", "媒體是外在的包含控制機制（External-Inclusive）", "組織紀律程序是內在的顯性控制機制（Internal-Explicit）", "社會化是內在的隱性控制機制（Internal-Implicit）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "09dc69c55c4f", "answer_pdf_sha1": "00e0858a8536", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1008", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00130', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '關於社區導向警政（Community-OrientedPolicing）與情報導向警政（Intelligence-LedPolicing）兩 者比較，下列何者錯誤？', '["就資訊管理而言：社區導向警政蒐集資訊的目的是界定社區問題；情報導向警政的資訊是為了 情報分析（intelligenceanalysis）", "就警民雙向溝通而言：社區導向警政蒐集犯罪者資訊，幫助民眾預防犯罪、降低恐懼；情報導 向警政在經由特定資訊篩選出可能的威脅，通知民眾，以防止恐怖攻擊，亦可降低恐懼", "就科學化的資料分析而言：社區導向警政的分析犯罪乃威脅管理（threatmanagement）中主要 成分；情報導向警政的犯罪分析乃電腦統計警政（COMPSTAT）過程中主要成分", "就問題解決而言：社區導向警政要解決的是社區內的犯罪與失序問題；情報導向警政使用情報， 消除脆弱目標的潛在因素"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "09dc69c55c4f", "answer_pdf_sha1": "00e0858a8536", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1008", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00131', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '關於現代新古典學派（ModernNeo-classicalCriminology）犯罪預防策略的說明，下列何者錯誤？', '["延續自古典學派中的一般嚇阻、特別嚇阻策略", "因社會控制理論的提出，逐步激盪產生情境犯罪預防策略", "現代新古典學派發展出由內而外的系統性犯罪預防策略", "透過同生群研究（cohortstudy）發現慢性犯罪人（chronicoffender）、核心犯罪人（hard-cord criminal）的概念，進而導出長期監禁的犯罪預防策略"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "09dc69c55c4f", "answer_pdf_sha1": "00e0858a8536", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1008", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00132', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '約會性侵害案件，多在特定的情境之下發生，運用情境犯罪預防的策略，對此類型犯罪能發揮功效。 有學者將約會性侵害有關的四個英文單字，組合成為STOP口訣，下列何者不是該口訣的內涵？', '["S代表安全（Security）", "T代表時間（Time）", "O代表機會（Opportunity）", "P代表人（Person）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "09dc69c55c4f", "answer_pdf_sha1": "00e0858a8536", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1008", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00133', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '關於「標準模式警政」（StandardmodelPolicing）以及「情資主導警政」（Intelligence-LedPolicing） 的敘述，下列何者錯誤？', '["標準模式警政採取主動反應作為", "標準模式警政著重犯罪發生後的偵辦追緝，輕忽犯罪發生前的危害防止", "情資主導警政以大數據的方式進行情資蒐集及分析工作", "強力執法也是情資主導警政採用的反應策略"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "09dc69c55c4f", "answer_pdf_sha1": "00e0858a8536", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1008", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00134', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '犯罪預防的風險管理模式是指，在風險社會之下，市民為自身的安全而立於風險管理的位子上， 有關該模式的犯罪預防策略，下列敘述何者錯誤？', '["將犯罪作為一種風險因素進行評估", "須排除私人因素", "尋求日常生活程序的修正", "使公民為犯罪負責"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "09dc69c55c4f", "answer_pdf_sha1": "00e0858a8536", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1008", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00135', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', 'CompStat警政又稱為電腦導向的犯罪統計，警察基金會曾提出CompStat的六個關鍵因素，下列 何者錯誤？', '["警察任務闡明", "保持組織靈活與彈性", "警察內部的責任", "內部的訊息交換"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "09dc69c55c4f", "answer_pdf_sha1": "00e0858a8536", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1008", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00136', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', 'Brantingham與Faust（1976）將三級預防模式引用的犯罪預防領域中，在初級犯罪預防的重要內 涵中，下列何者不是該層級所採用的措施？', '["環境設計", "犯防宣導", "私人保全", "社區警政"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "09dc69c55c4f", "answer_pdf_sha1": "00e0858a8536", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1008", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL)
